    setTimeout(() => {
      const tmp = fromAirport;
      const tmpInput = fromInput;
      setFromAirport(toAirport);
      setToAirport(tmp);
      setFromInput(toInput);
      setToInput(tmpInput);
      setSwapping(false);
    }, 150);
